import {
  XYChartThresholdDynamicProps,
  XYChartThresholdIndicatorProps,
} from '../../types/xy-chart-props.js';
import {
  XYChartThresholdData,
  type XYChartThresholdRangeBase,
} from '../../types/xy-chart.js';

/**
 * Type guard to check if a given object is of type DataRangeStatic.
 *
 * @param obj - The object to check.
 * @returns True if the object is a DataRangeStatic, false otherwise.
 */
export const isDataRange = (
  obj: XYChartThresholdData,
): obj is XYChartThresholdRangeBase => {
  return (
    typeof obj === 'object' && obj !== null && 'yMin' in obj && 'yMax' in obj
  );
};

export const isThresholdDynamic = (
  obj: XYChartThresholdIndicatorProps,
): obj is XYChartThresholdDynamicProps => {
  return 'xAxisId' in obj && Array.isArray(obj.data);
};
